const triggerData = $("When Executed by Another Workflow").first().json;

const mode = triggerData.mode || "suggestion";
const personCode = triggerData.holland_code || "";
const userSkills = Array.isArray(triggerData.skills) ? triggerData.skills : [];
const chosenCareerId = triggerData.chosen_career_id || null;

// rows من Google Sheets
const rawRows = items.map(item => item.json);

if (!rawRows.length) {
  return [
    {
      json: {
        mode,
        careers: [],
        error: "No rows returned from Google Sheets"
      }
    }
  ];
}

// ==============================
// HELPERS
// ==============================
const norm = (s) => String(s || "").trim().toLowerCase();

function uniqueArray(arr) {
  const seen = new Set();
  const result = [];

  for (const item of arr) {
    const value = String(item || "").trim();
    const key = norm(value);

    if (!value || seen.has(key)) continue;
    seen.add(key);
    result.push(value);
  }

  return result;
}

function toSet(arr) {
  return new Set(arr.map(norm).filter(Boolean));
}

function splitSkills(text) {
  if (!text) return [];

  return String(text)
    .split(/\s*-\s*|\n/)
    .map(s => s.trim())
    .filter(Boolean);
}

function getField(obj, name) {
  const key = Object.keys(obj).find(k => k.trim() === name);
  return key ? obj[key] : "";
}

// ==============================
// CLEAN RAW SHEET ROWS
// ==============================
const jobs = rawRows.map(job => ({
  career_id: job.career_id || null,
  job_title: job.job_title || "",
  job_family: job.job_family || "",
  holland_code: job.holland_code || "",
  beginner: uniqueArray(splitSkills(job.beginner_level || "")),
  intermediate: uniqueArray(splitSkills(job.intermediate_level || ""))
}));
// ==============================
// HOLLAND C-INDEX
// ==============================
function cIndex(personCode, jobCode) {
  const a = String(personCode || "").toUpperCase().split("");
  const b = String(jobCode || "").toUpperCase().split("");
  const ria = ["R", "I", "A", "S", "E", "C"];

  function wrapIndex(n) {
    let temp = n % 6;
    if (temp < 0) temp += 6;
    return temp;
  }

  let total = 0;
  const maxLen = Math.min(3, a.length, b.length);

  for (let i = 0; i < maxLen; i++) {
    const p = a[i];
    const u = b[i];
    let score = 0;

    if (p === u) {
      score = 3;
    } else {
      const pos = ria.indexOf(p);
      if (pos === -1) continue;

      const left1 = ria[wrapIndex(pos - 1)];
      const right1 = ria[wrapIndex(pos + 1)];
      const left2 = ria[wrapIndex(pos - 2)];
      const right2 = ria[wrapIndex(pos + 2)];

      if (u === left1 || u === right1) score = 2;
      else if (u === left2 || u === right2) score = 1;
    }

    total += score * (3 - i);
  }

  return total;
}

// ==============================
// JACCARD SKILLS
// ==============================
function jaccardSimilarity(a, b) {
  const A = new Set(a.map(norm).filter(Boolean));
  const B = new Set(b.map(norm).filter(Boolean));

  const intersection = new Set([...A].filter(x => B.has(x)));
  const union = new Set([...A, ...B]);

  if (union.size === 0) return 0;
  return intersection.size / union.size;
}

// ==============================
// STAGE 1: HOLLAND SCORING
// ==============================
let hollandScored = jobs.map(job => {
  const score = cIndex(personCode, job.holland_code);
  const pct = Math.round((score / 18) * 100);

  return {
    ...job,
    holland_percentage: pct
  };
});

hollandScored.sort((a, b) => b.holland_percentage - a.holland_percentage);

// ==============================
// MANUAL MODE
// ==============================
if (mode === "manual") {
  const chosen = hollandScored.find(
    j => String(j.career_id) === String(chosenCareerId)
  );

  if (!chosen) {
    return [
      {
        json: {
          mode: "manual",
          career: null,
          error: "Chosen career not found"
        }
      }
    ];
  }

  const jobSkills = uniqueArray([
    ...chosen.beginner,
    ...chosen.intermediate
  ]);

  const jsim = jaccardSimilarity(userSkills, jobSkills);
  const spct = Math.round(jsim * 100);

  const userSet = toSet(userSkills);
  const matched = jobSkills.filter(skill => userSet.has(norm(skill)));
  const missing = jobSkills.filter(skill => !userSet.has(norm(skill)));

  const overall = Math.round(
    (chosen.holland_percentage * 0.5) + (spct * 0.5)
  );

  return [
    {
      json: {
        mode: "manual",
        career: {
          career_id: chosen.career_id,
          career_title: chosen.job_title,
          job_family: chosen.job_family,
          holland_code: chosen.holland_code,
          overall_match: overall,
          holland_match: chosen.holland_percentage,
          skills_match: spct,
          strengths: matched,
          gaps: missing
        }
      }
    }
  ];
}
// ==============================
// SUGGESTION MODE
// أفضل 6 بالهولاند ثم أفضل 3 بالمهارات
// ==============================
const top6 = hollandScored.slice(0, 6);

function scoreSkills(job) {
  const jobSkills = uniqueArray([
    ...job.beginner,
    ...job.intermediate
  ]);

  const jsim = jaccardSimilarity(userSkills, jobSkills);
  const spct = Math.round(jsim * 100);

  const userSet = toSet(userSkills);
  const matched = jobSkills.filter(skill => userSet.has(norm(skill)));
  const missing = jobSkills.filter(skill => !userSet.has(norm(skill)));

  const overall = Math.round(
    (job.holland_percentage * 0.5) + (spct * 0.5)
  );

  return {
    career_id: job.career_id,
    career_title: job.job_title,
    job_family: job.job_family,
    holland_code: job.holland_code,
    overall_match: overall,
    holland_match: job.holland_percentage,
    skills_match: spct,
    strengths: matched,
    gaps: missing
  };
}

const top3 = top6
  .map(scoreSkills)
  .sort((a, b) => b.overall_match - a.overall_match)
  .slice(0, 3);

return [
  {
    json: {
      mode: "suggestion",
      careers: top3
    }
  }
];
